                    var mbPost = new T.Mesh(new T.CylinderGeometry(0.04, 0.04, 1.0, 5), new T.MeshLambertMaterial({ color: 0x78350f }));
                    mbPost.position.set(ambX, 0.5, ambZ);
                    chunkGroup.add(mbPost);
