                    var pcCabin = new T.Mesh(new T.BoxGeometry(0.9, 0.45, 0.65), new T.MeshLambertMaterial({ color: Math.max(0, parkedColor - 0x202020) }));
                    pcCabin.position.set(parkedCarX + 0.05, 1.05, ambZ);
                    chunkGroup.add(pcCabin);
