                  var mist = new T.Mesh(new T.PlaneGeometry(12, 4), mistMat);
                  mist.rotation.x = -Math.PI / 2;
                  mist.position.set((weatherRng() - 0.5) * 4, 0.3, mistZ);
                  chunkGroup.add(mist);
