              if (nearestSig.state === 'red') { gfx.fillStyle = 'rgba(239,68,68,0.3)'; gfx.beginPath(); gfx.arc(tlX, tlY - 9, 8, 0, Math.PI * 2); gfx.fill(); }
              // Yellow lamp
